+function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Backrest frame with ornate gold wood grain and studs
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(4, 0, 20, 28);
+  ctx.strokeStyle = '#a67c00';
+  ctx.lineWidth = 1;
+  for (let i = 5; i < 24; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 2);
+    ctx.lineTo(i - 2, 10);
+    ctx.stroke();
+  }
+  // Wood grain texture with darker streaks
+  ctx.strokeStyle = '#bfa03e';
+  for (let i = 6; i < 24; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 4);
+    ctx.lineTo(i - 1, 12);
+    ctx.stroke();
+  }
+  // Metal studs on frame edges
+  ctx.fillStyle = '#8a6f1a';
+  for (let i = 6; i < 24; i += 6) {
+    ctx.beginPath();
+    ctx.arc(i, 4, 1, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.arc(i, 24, 1, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  // Cushion (red velvet with fabric folds and shading)
+  ctx.fillStyle = '#a32a2a';
+  ctx.fillRect(6, 18, 16, 10);
+  ctx.fillStyle = '#7a1a1a';
+  ctx.fillRect(6, 23, 16, 5);
+  // Fabric folds (lines)
+  ctx.strokeStyle = '#7a1a1a';
+  ctx.lineWidth = 0.5;
+  for (let i = 7; i < 22; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 18);
+    ctx.lineTo(i - 2, 28);
+    ctx.stroke();
+  }
+  // Decorative top arch with gradient fill and shadow
+  const grad = ctx.createLinearGradient(4, 0, 24, 0);
+  grad.addColorStop(0, '#d4af37');
+  grad.addColorStop(0.5, '#f0d75e');
+  grad.addColorStop(1, '#d4af37');
+  ctx.fillStyle = grad;
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -12, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+  ctx.fillStyle = 'rgba(0,0,0,0.15)';
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -10, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+  // Legs with shadows and highlights
+  ctx.fillStyle = '#bfa03e';
+  ctx.fillRect(4, 28, 6, 4);
+  ctx.fillRect(18, 28, 6, 4);
+  ctx.strokeStyle = '#8a6f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(4, 28, 6, 4);
+  ctx.strokeRect(18, 28, 6, 4);
+  // Leg shadows
+  ctx.fillStyle = 'rgba(0,0,0,0.2)';
+  ctx.fillRect(4, 32, 6, 2);
+  ctx.fillRect(18, 32, 6, 2);
+  ctx.restore();
+}
