+function drawWorkbench(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Bench top with wood grain texture and knots
+  ctx.fillStyle = '#7a5230';
+  ctx.fillRect(0, 8, 32, 12);
+  ctx.strokeStyle = '#6a4320';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 30; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Wood grain knots (small dark spots)
+  ctx.fillStyle = '#5a3f21';
+  for (let i = 4; i < 28; i += 6) {
+    ctx.beginPath();
+    ctx.ellipse(i, 14, 1.5, 2, 0, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  // Legs with shading and metal braces
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(24, 20, 6, 4);
+  ctx.strokeStyle = '#4a2f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(24, 20, 6, 4);
+  ctx.fillStyle = '#3a2a1a';
+  ctx.fillRect(2, 22, 6, 1);
+  ctx.fillRect(24, 22, 6, 1);
+  // Hammer with wood handle and metal head with shine
+  ctx.strokeStyle = '#3a2f2a';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(8, 14);
+  ctx.lineTo(8, 18);
+  ctx.moveTo(6, 18);
+  ctx.lineTo(10, 18);
+  ctx.stroke();
+  ctx.fillStyle = '#5a4a40';
+  ctx.fillRect(5, 13, 6, 2);
+  ctx.fillStyle = '#7a6a50';
+  ctx.fillRect(7, 12, 2, 2);
+  // Saw blade with jagged teeth and metal shine
+  ctx.fillStyle = '#a0a0a0';
+  ctx.beginPath();
+  ctx.moveTo(20, 14);
+  for (let i = 0; i < 5; i++) {
+    ctx.lineTo(20 + i * 2, 14 + (i % 2 === 0 ? 4 : 0));
+  }
+  ctx.lineTo(30, 18);
+  ctx.closePath();
+  ctx.fill();
+  ctx.strokeStyle = '#7a7a7a';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  for (let i = 0; i < 5; i++) {
+    ctx.moveTo(20 + i * 2, 14);
+    ctx.lineTo(20 + i * 2, 18);
+  }
+  ctx.stroke();
+  // Saw teeth highlights
+  ctx.strokeStyle = '#c0c0c0';
+  ctx.lineWidth = 0.5;
+  for (let i = 0; i < 5; i++) {
+    ctx.beginPath();
+    ctx.moveTo(20 + i * 2 + 1, 16);
+    ctx.lineTo(20 + i * 2 + 1, 18);
+    ctx.stroke();
+  }
+  ctx.restore();
+}
