+function drawScribeDesk(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Desk top with dark wood grain and scratches
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#4a2f10';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 28; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Wood grain scratches
+  ctx.strokeStyle = '#3a2a10';
+  for (let i = 4; i < 26; i += 5) {
+    ctx.beginPath();
+    ctx.moveTo(i, 12);
+    ctx.lineTo(i - 1, 16);
+    ctx.stroke();
+  }
+  // Legs with shading and metal brackets
+  ctx.fillStyle = '#4a2f10';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(22, 20, 6, 4);
+  ctx.strokeStyle = '#3a2010';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(22, 20, 6, 4);
+  ctx.fillStyle = '#2a1a00';
+  ctx.fillRect(2, 22, 6, 1);
+  ctx.fillRect(22, 22, 6, 1);
+  // Open book with cream pages and fine lines
+  ctx.fillStyle = '#f9f4d7';
+  ctx.fillRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#d9d1a3';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#a3a375';
+  for (let yline = 12; yline < 17; yline += 2) {
+    ctx.beginPath();
+    ctx.moveTo(7, yline);
+    ctx.lineTo(23, yline);
+    ctx.stroke();
+  }
+  // Quill with feather details and black tip
+  ctx.strokeStyle = '#222';
+  ctx.lineWidth = 1;
+  ctx.fillStyle = '#eee';
+  ctx.beginPath();
+  ctx.moveTo(24, 12);
+  ctx.lineTo(28, 8);
+  ctx.lineTo(26, 6);
+  ctx.lineTo(22, 10);
+  ctx.closePath();
+  ctx.fill();
